/**
 * @summary Get the chronological audit timeline for a single employee
 */
export const getGetEmployeeTimelineUrl = (
  orgId: number,
  id: number,
  params?: GetEmployeeTimelineParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/employees/${id}/timeline?${stringifiedParams}`
    : `/api/organizations/${orgId}/employees/${id}/timeline`;
};

