/**
 * @summary Get recent activity in the organization
 */
export const getGetRecentActivityUrl = (
  orgId: number,
  params?: GetRecentActivityParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/recent-activity?${stringifiedParams}`
    : `/api/organizations/${orgId}/recent-activity`;
};

