/**
 * @summary List saved filter views for the current user in this organization
 */
export const getListSavedFilterViewsUrl = (
  orgId: number,
  params?: ListSavedFilterViewsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/saved-filter-views?${stringifiedParams}`
    : `/api/organizations/${orgId}/saved-filter-views`;
};

