/**
 * Returns up to a small number of matching employees and departments for the
given organization. Used by the global Cmd+K command palette to keep
cold-start lookups fast on large orgs without paging the full list.

 * @summary Lightweight permission-scoped search across employees and departments
 */
export const getSearchOrganizationUrl = (
  orgId: number,
  params: SearchOrganizationParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/search?${stringifiedParams}`
    : `/api/organizations/${orgId}/search`;
};

export const searchOrganization = async (
  orgId: number,
  params: SearchOrganizationParams,
  options?: RequestInit,
): Promise<SearchResults> => {
  return customFetch<SearchResults>(getSearchOrganizationUrl(orgId, params), {
    ...options,
    method: "GET",
  });
};

export const getSearchOrganizationQueryKey = (
  orgId: number,
  params?: SearchOrganizationParams,
) => {
  return [
    `/api/organizations/${orgId}/search`,
    ...(params ? [params] : []),
  ] as const;
};

export const getSearchOrganizationQueryOptions = <
  TData = Awaited<ReturnType<typeof searchOrganization>>,
  TError = ErrorType<unknown>,
>(
  orgId: number,
  params: SearchOrganizationParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof searchOrganization>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getSearchOrganizationQueryKey(orgId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof searchOrganization>>
  > = ({ signal }) =>
    searchOrganization(orgId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!orgId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof searchOrganization>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

